channels = get_channels()

matching_channels = [channel for channel in channels if channel.lower().startswith("external")]
if len(matching_channels) == 0:
    raise ValueError("No channel starts with 'External'.")

exact_channel_matches = [channel for channel in matching_channels if channel.lower() == "external"]
if len(matching_channels) == 1:
    target_channel = matching_channels[0]
elif len(exact_channel_matches) == 1:
    target_channel = exact_channel_matches[0]
else:
    raise NotEnoughInformationError("Multiple channels start with 'External'.")

all_users = sorted(set([user for channel in channels for user in get_users_in_channel(channel)]))

exact_user_matches = [user for user in all_users if user.lower() == "charlie"]
prefix_user_matches = [user for user in all_users if user.lower().startswith("charlie")]

if len(exact_user_matches) == 1:
    target_user = exact_user_matches[0]
elif len(exact_user_matches) > 1:
    raise NotEnoughInformationError("Multiple users named 'Charlie' were found.")
elif len(prefix_user_matches) == 1:
    target_user = prefix_user_matches[0]
elif len(prefix_user_matches) > 1:
    raise NotEnoughInformationError("Multiple users whose names start with 'Charlie' were found.")
else:
    raise ValueError("No user matching 'Charlie' was found.")

channel_users = get_users_in_channel(target_channel)

if target_user in channel_users:
    print("{} is already in {}.".format(target_user, target_channel))
else:
    add_user_to_channel(target_user, target_channel)
    print("Added {} to {}.".format(target_user, target_channel))
